-- ============================================================================
-- FOUNDATION PATH: Future Simple Tense (COMPLETE)
-- Topic ID: future-simple
-- Level: beginner (A1)
-- Total: 100 questions covering ALL 5 subtopics
-- ============================================================================
-- Subtopics covered:
--   1. will + base verb (basic structure) - 20 questions
--   2. going to + base verb (planned future) - 20 questions
--   3. Negative & Questions - 20 questions
--   4. Predictions vs Plans (will vs going to) - 20 questions
--   5. Time Expressions: tomorrow, next, soon - 20 questions
-- Distribution: 40 easy, 40 medium, 20 hard per 100 questions
-- ============================================================================

INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: will + base verb (basic structure) - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'future-simple', 'beginner', 'I _____ go to Delhi tomorrow.', '["will", "shall", "going", "went"]', 0, 'Future simple: will + base verb. I + will + go. "Will" works with all subjects. Shows future action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'She _____ call you later.', '["will", "shall", "going", "called"]', 0, 'Future simple: will + base verb. She + will + call. Same "will" for all subjects. Future action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'They _____ finish the work.', '["will", "shall", "going", "finished"]', 0, 'Future simple: will + base verb. They + will + finish. Universal "will" for future. Future action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'He _____ help you.', '["will", "shall", "going", "helped"]', 0, 'Future simple: will + base verb. He + will + help. "Will" = future promise/offer. Future action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'We _____ watch the movie.', '["will", "shall", "going", "watched"]', 0, 'Future simple: will + base verb. We + will + watch. "Will" for future plans. Future action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'You _____ like this book.', '["will", "shall", "going", "liked"]', 0, 'Future simple: will + base verb. You + will + like. "Will" for predictions. Future state.', 'easy'),

('foundation', 'future-simple', 'beginner', 'It _____ rain tomorrow.', '["will", "shall", "going", "rained"]', 0, 'Future simple: will + base verb. It + will + rain. "Will" for weather predictions. Future event.', 'easy'),

('foundation', 'future-simple', 'beginner', 'The teacher _____ explain it.', '["will", "shall", "going", "explained"]', 0, 'Future simple: will + base verb. Teacher + will + explain. "Will" for future actions. Future action.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'future-simple', 'beginner', 'What is wrong? "I will goes to Delhi."', '["Use go instead of goes", "Use going instead of goes", "Use went instead of goes", "Nothing wrong"]', 0, 'Future simple: will + BASE verb (no -s). Correct: "I will go to Delhi." Don''t add -s/-es after will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the correct sentence:', '["She will calls you.", "She will call you.", "She will called you.", "She will calling you."]', 1, 'Future simple: will + base verb. Correct: "She will call you." Base form only (no -s, -ed, -ing) after will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: tomorrow / will / I / Delhi / to / go', '["I will go to Delhi tomorrow", "I will to Delhi go tomorrow", "Tomorrow I will go to Delhi", "I to Delhi will go tomorrow"]', 0, 'Pattern: Subject + will + base verb + to + place + time. Order: I will go to Delhi tomorrow. Natural word order.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is the error? "They will finished the work."', '["Use finish instead of finished", "Use finishing instead of finished", "Use finishes instead of finished", "Nothing wrong"]', 0, 'Future simple: will + BASE verb (not past). Correct: "They will finish the work." Use base form after will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Making a promise:', '["I help you tomorrow.", "I helped you tomorrow.", "I will help you tomorrow.", "I helping you tomorrow."]', 2, 'Future simple for promises: will + base verb. Correct: "I will help you tomorrow." Will = promise/offer.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Rearrange: next / call / She / week / will / you', '["She will call you next week", "She will you call next week", "Next week she will call you", "She call will you next week"]', 0, 'Pattern: Subject + will + base verb + object + time. Order: She will call you next week. Natural structure.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the natural sentence:', '["He will works hard.", "He will work hard.", "He will worked hard.", "He will working hard."]', 1, 'Future simple: will + base verb. Correct: "He will work hard." Only base form after will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "We will going to the party."', '["Use go instead of going", "Use went instead of going", "Use goes instead of going", "Nothing wrong"]', 0, 'Future simple: will + BASE verb (not -ing). Correct: "We will go to the party." Use base form after will.', 'medium'),

-- HARD (4 questions)
('foundation', 'future-simple', 'beginner', 'Which is correct formal writing?', '["The meeting start tomorrow.", "The meeting will start tomorrow.", "The meeting will starts tomorrow.", "The meeting starting tomorrow."]', 1, 'Future simple: will + base verb. Correct: "The meeting will start tomorrow." Formal writing uses will for future.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Find the error: "Each student will submits their work."', '["Use submit instead of submits", "Use submitted instead of submits", "Use submitting instead of submits", "No error"]', 0, 'Future simple: will + BASE verb (no -s). Correct: "Each student will submit their work." Don''t add -s after will.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: report / complete / will / the / We / month / next', '["We will complete the report next month", "We will complete next month the report", "Next month we will complete the report", "We the report will complete next month"]', 0, 'Pattern: Subject + will + base verb + object + time. Natural: We will complete the report next month. Both orders work.', 'hard'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "The team will meets tomorrow."', '["Use meet instead of meets", "Use met instead of meets", "Use meeting instead of meets", "Nothing wrong"]', 0, 'Future simple: will + BASE verb (no -s). Correct: "The team will meet tomorrow." Don''t add -s after will.', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: going to + base verb (planned future) - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'future-simple', 'beginner', 'I _____ going to visit Delhi.', '["am", "is", "are", "will"]', 0, 'Going to future: am/is/are + going to + base verb. I + am + going to + visit. Planned future.', 'easy'),

('foundation', 'future-simple', 'beginner', 'She _____ going to call you.', '["am", "is", "are", "will"]', 1, 'Going to future: am/is/are + going to + base verb. She + is + going to + call. Planned action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'They _____ going to study.', '["am", "is", "are", "will"]', 2, 'Going to future: am/is/are + going to + base verb. They + are + going to + study. Planned future.', 'easy'),

('foundation', 'future-simple', 'beginner', 'He _____ going to help you.', '["am", "is", "are", "will"]', 1, 'Going to future: am/is/are + going to + base verb. He + is + going to + help. Planned action.', 'easy'),

('foundation', 'future-simple', 'beginner', 'We _____ going to watch the movie.', '["am", "is", "are", "will"]', 2, 'Going to future: am/is/are + going to + base verb. We + are + going to + watch. Planned future.', 'easy'),

('foundation', 'future-simple', 'beginner', 'You _____ going to love this.', '["am", "is", "are", "will"]', 2, 'Going to future: am/is/are + going to + base verb. You + are + going to + love. Future prediction with evidence.', 'easy'),

('foundation', 'future-simple', 'beginner', 'It _____ going to rain.', '["am", "is", "are", "will"]', 1, 'Going to future: am/is/are + going to + base verb. It + is + going to + rain. Prediction with evidence (clouds).', 'easy'),

('foundation', 'future-simple', 'beginner', 'My parents _____ going to arrive soon.', '["am", "is", "are", "will"]', 2, 'Going to future: am/is/are + going to + base verb. Parents (plural) + are + going to + arrive. Planned arrival.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'future-simple', 'beginner', 'What is wrong? "I is going to visit Delhi."', '["Use am instead of is", "Use are instead of is", "Use will instead of is", "Nothing wrong"]', 0, 'Subject-verb agreement: I + am (not "is"). Correct: "I am going to visit Delhi." I = am, he/she/it = is, you/we/they = are.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the correct sentence:', '["She going to call you.", "She is going call you.", "She is going to call you.", "She is going to calls you."]', 2, 'Going to future: is + going to + BASE verb. Correct: "She is going to call you." Need is + going to + base.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: tomorrow / going / am / to / I / Delhi / visit', '["I am going to visit Delhi tomorrow", "I am going to Delhi visit tomorrow", "Tomorrow I am going to visit Delhi", "I going am to visit Delhi tomorrow"]', 0, 'Pattern: Subject + am/is/are + going to + base verb + object + time. Order: I am going to visit Delhi tomorrow. Natural structure.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is the error? "They is going to finish the work."', '["Use are instead of is", "Use am instead of is", "Use will instead of is", "Nothing wrong"]', 0, 'Subject-verb agreement: They + are (not "is"). Correct: "They are going to finish the work." Plural = are.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Announcing your plan:', '["I visit Mumbai next week.", "I visited Mumbai next week.", "I am going to visit Mumbai next week.", "I visiting Mumbai next week."]', 2, 'Going to for plans: am + going to + base verb. Correct: "I am going to visit Mumbai next week." Pre-decided plan.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Rearrange: movie / going / to / We / watch / are / the', '["We are going to watch the movie", "We are going to the movie watch", "Going to watch we are the movie", "We to watch are going the movie"]', 0, 'Pattern: Subject + are + going to + base verb + object. Order: We are going to watch the movie. Natural structure.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the natural sentence:', '["He going to work hard.", "He is going work hard.", "He is going to work hard.", "He is going to works hard."]', 2, 'Going to future: is + going to + BASE verb. Correct: "He is going to work hard." Need all three parts.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "We going to the party."', '["Add are: We are going to go to the party", "Add is: We is going to the party", "Add will: We will going to the party", "Nothing wrong"]', 0, 'Missing verb! Need are + going to + BASE VERB. Correct: "We are going to go to the party." Or "We are going to the party" (going = verb).', 'medium'),

-- HARD (4 questions)
('foundation', 'future-simple', 'beginner', 'Which correctly shows pre-planned action?', '["The company will launch next month.", "The company is going to launch next month.", "Both mean the same", "Neither is correct"]', 1, 'Going to = pre-planned. Will = spontaneous decision. "Is going to launch" = already planned launch. Pre-decided action!', 'hard'),

('foundation', 'future-simple', 'beginner', 'Find the error: "Each student are going to present."', '["Use is instead of are", "Use am instead of are", "Use will instead of are", "No error"]', 0, 'Subject-verb agreement: "Each student" = singular = is. Correct: "Each student is going to present." Each = singular.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: exam / take / going / the / to / are / They / next / week', '["They are going to take the exam next week", "They are going to the exam take next week", "Next week they are going to take the exam", "They going to are take the exam next week"]', 0, 'Pattern: Subject + are + going to + base verb + object + time. Natural: They are going to take the exam next week. Both orders work.', 'hard'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "The team are going to wins."', '["Use is instead of are AND use win instead of wins", "Use is instead of are", "Use win instead of wins", "Nothing wrong"]', 0, 'Two errors: "Team" = singular = is (not are). Going to + BASE verb (not wins). Correct: "The team is going to win."', 'hard'),

-- ============================================================================
