-- ============================================================================

-- EASY (8 questions)
('foundation', 'future-simple', 'beginner', 'I _____ not go to the party.', '["will", "shall", "going", "went"]', 0, 'Future negative: will + not + base verb. I + will + not + go. Pattern: will not go (won''t go).', 'easy'),

('foundation', 'future-simple', 'beginner', 'She _____ not call you.', '["will", "shall", "going", "called"]', 0, 'Future negative: will + not + base verb. She + will + not + call. Pattern: will not call (won''t call).', 'easy'),

('foundation', 'future-simple', 'beginner', '_____ you come tomorrow?', '["Will", "Shall", "Going", "Do"]', 0, 'Future question: Will + subject + base verb? Will + you + come. Pattern: Will you come?', 'easy'),

('foundation', 'future-simple', 'beginner', '_____ she help us?', '["Will", "Shall", "Going", "Does"]', 0, 'Future question: Will + subject + base verb? Will + she + help. Pattern: Will she help?', 'easy'),

('foundation', 'future-simple', 'beginner', 'They _____ not finish on time.', '["will", "shall", "going", "finished"]', 0, 'Future negative: will + not + base verb. They + will + not + finish. Pattern: will not finish (won''t finish).', 'easy'),

('foundation', 'future-simple', 'beginner', '_____ it rain tomorrow?', '["Will", "Shall", "Going", "Does"]', 0, 'Future question: Will + subject + base verb? Will + it + rain. Pattern: Will it rain?', 'easy'),

('foundation', 'future-simple', 'beginner', 'He _____ not attend the meeting.', '["will", "shall", "going", "attended"]', 0, 'Future negative: will + not + base verb. He + will + not + attend. Pattern: will not attend (won''t attend).', 'easy'),

('foundation', 'future-simple', 'beginner', '_____ they arrive soon?', '["Will", "Shall", "Going", "Do"]', 0, 'Future question: Will + subject + base verb? Will + they + arrive. Pattern: Will they arrive?', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'future-simple', 'beginner', 'What is wrong? "I will not goes to Delhi."', '["Use go instead of goes", "Use going instead of goes", "Use went instead of goes", "Nothing wrong"]', 0, 'Future negative: will not + BASE verb (no -s). Correct: "I will not go to Delhi." Base form after will not.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the correct sentence:', '["She will not calls you.", "She will not call you.", "She not will call you.", "She will not called you."]', 1, 'Future negative: will + not + base verb. Correct: "She will not call you." Natural: won''t call you.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: go / Will / to / you / party / the', '["Will you go to the party", "You will go to the party", "Will go you to the party", "To the party will you go"]', 0, 'Future question: Will + subject + base verb + to + place. Order: Will you go to the party? Question structure.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is the error? "They will not finished the work."', '["Use finish instead of finished", "Use finishing instead of finished", "Use finishes instead of finished", "Nothing wrong"]', 0, 'Future negative: will not + BASE verb (not past). Correct: "They will not finish the work." Base form only.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Asking about someone''s plans:', '["You will come tomorrow?", "Will you come tomorrow?", "Will you comes tomorrow?", "You will coming tomorrow?"]', 1, 'Future question: Will + subject + base verb. Correct: "Will you come tomorrow?" Formal question structure.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Rearrange: meeting / the / not / attend / She / will', '["She will not attend the meeting", "She not will attend the meeting", "Will she not attend the meeting", "She will attend not the meeting"]', 0, 'Future negative: Subject + will + not + base verb + object. Order: She will not attend the meeting. Natural: won''t attend.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the natural sentence:', '["He will not works tomorrow.", "He will not work tomorrow.", "He not will work tomorrow.", "He will not working tomorrow."]', 1, 'Future negative: will + not + BASE verb. Correct: "He will not work tomorrow." Natural contraction: won''t work.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "Will they arrives on time?"', '["Use arrive instead of arrives", "Use arrived instead of arrives", "Use arriving instead of arrives", "Nothing wrong"]', 0, 'Future question: Will + BASE verb (no -s). Correct: "Will they arrive on time?" No -s after will in questions.', 'medium'),

-- HARD (4 questions)
('foundation', 'future-simple', 'beginner', 'Which is correct formal writing?', '["The meeting will not hold tomorrow.", "The meeting will not be held tomorrow.", "The meeting not will be held tomorrow.", "The meeting will not holding tomorrow."]', 1, 'Future negative passive: will not + be + V3. Correct: "The meeting will not be held tomorrow." Formal writing uses passive.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Find the error: "Will each student submits their work?"', '["Use submit instead of submits", "Use submitted instead of submits", "Use submitting instead of submits", "No error"]', 0, 'Future question: Will + BASE verb (no -s). Correct: "Will each student submit their work?" No -s after will.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: report / complete / Will / the / they / time / on', '["Will they complete the report on time", "They will complete the report on time", "Will complete they the report on time", "Will they the report complete on time"]', 0, 'Future question: Will + subject + base verb + object + time. Order: Will they complete the report on time? Question structure.', 'hard'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "The team will not meets tomorrow."', '["Use meet instead of meets", "Use met instead of meets", "Use meeting instead of meets", "Nothing wrong"]', 0, 'Future negative: will not + BASE verb (no -s). Correct: "The team will not meet tomorrow." Base form after will not.', 'hard'),

-- ============================================================================
-- SUBTOPIC 4: Predictions vs Plans (will vs going to) - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'future-simple', 'beginner', 'Making a spontaneous decision: A) I will help you. B) I am going to help you.', '["A (will)", "B (going to)", "Both mean the same", "Neither is correct"]', 0, 'Will = spontaneous decision (deciding now). Going to = pre-planned. "I will help you" = deciding at this moment.', 'easy'),

('foundation', 'future-simple', 'beginner', 'Pre-planned action: A) I will visit Mumbai next week. B) I am going to visit Mumbai next week.', '["A (will)", "B (going to)", "Both mean the same", "Neither is correct"]', 1, 'Going to = pre-planned action (already decided). Will = spontaneous. "I am going to visit" = already planned trip.', 'easy'),

('foundation', 'future-simple', 'beginner', 'The phone is ringing. I _____ answer it.', '["will", "am going to", "would", "can"]', 0, 'Spontaneous decision: will. "I will answer it" = deciding now (not pre-planned). Instant decision at that moment.', 'easy'),

('foundation', 'future-simple', 'beginner', 'I have bought tickets. We _____ watch the movie tonight.', '["will", "are going to", "would", "can"]', 1, 'Pre-planned action: going to. "We are going to watch" = already decided (have tickets). Evidence of plan!', 'easy'),

('foundation', 'future-simple', 'beginner', 'Promise: I _____ help you with your homework.', '["will", "am going to", "would", "can"]', 0, 'Promise = will. "I will help you" = making promise now. Will for promises/offers.', 'easy'),

('foundation', 'future-simple', 'beginner', 'Prediction with evidence (dark clouds): It _____ rain.', '["will", "is going to", "would", "can"]', 1, 'Prediction with evidence = going to. "It is going to rain" = evidence (clouds) shows it will rain. Visible signs!', 'easy'),

('foundation', 'future-simple', 'beginner', 'General prediction: I think she _____ pass the exam.', '["will", "is going to", "would", "can"]', 0, 'General prediction = will. "I think she will pass" = opinion/belief (no evidence). Will for opinions.', 'easy'),

('foundation', 'future-simple', 'beginner', 'Scheduled plan: The train _____ arrive at 5 PM.', '["will", "is going to", "would", "can"]', 0, 'Scheduled events = will (or present simple). "The train will arrive" = timetabled event. Schedule = will.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'future-simple', 'beginner', 'What''s the difference? A) "I will study tonight." B) "I am going to study tonight."', '["A = deciding now, B = already decided", "A = already decided, B = deciding now", "Both mean the same", "Both are wrong"]', 0, 'Will = spontaneous decision (deciding now). Going to = pre-planned (already decided earlier). Timing of decision matters!', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the correct response: "Can you help me?" - "Sure, I _____ help you."', '["will", "am going to", "would", "can"]', 0, 'Spontaneous offer = will. "I will help you" = offering now (not pre-planned). Instant response uses will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Announcing pre-decided plan:', '["I will join the company next month.", "I am going to join the company next month.", "Both are correct", "Neither is correct"]', 1, 'Pre-planned action = going to. "I am going to join" = already accepted offer/decided. Evidence: next month (planned).', 'medium'),

('foundation', 'future-simple', 'beginner', 'Prediction based on current situation (someone walking toward door):', '["She will leave.", "She is going to leave.", "Both are correct", "Neither is correct"]', 1, 'Prediction with evidence = going to. "She is going to leave" = evidence (walking to door). Visible signs = going to.', 'medium'),

('foundation', 'future-simple', 'beginner', 'General opinion:', '["I think it will rain tomorrow.", "I think it is going to rain tomorrow.", "Both mean the same", "Neither is correct"]', 0, 'Opinion/belief = will. "I think it will rain" = personal prediction (no evidence). Think/believe/hope = will.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Promise in formal email:', '["We will send the report by Friday.", "We are going to send the report by Friday.", "Both are correct", "Neither is correct"]', 0, 'Formal promise = will. "We will send" = commitment/promise. Formal writing prefers will for promises.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Someone carrying heavy bags, about to fall:', '["He will drop them.", "He is going to drop them.", "Both mean the same", "Neither is correct"]', 1, 'Prediction with evidence = going to. "He is going to drop them" = visible evidence (struggling). Immediate evidence!', 'medium'),

('foundation', 'future-simple', 'beginner', 'Making spontaneous offer at restaurant:', '["I will pay for dinner.", "I am going to pay for dinner.", "Both mean the same", "Neither is correct"]', 0, 'Spontaneous offer = will. "I will pay" = deciding now (not pre-planned). Instant generous offer uses will.', 'medium'),

-- HARD (4 questions)
('foundation', 'future-simple', 'beginner', 'Which is more natural? "The sky is dark. It _____ rain."', '["will", "is going to", "Both equally natural", "Neither is correct"]', 1, 'Prediction with evidence = going to more natural. "It is going to rain" = evidence (dark sky). Going to emphasizes evidence!', 'hard'),

('foundation', 'future-simple', 'beginner', 'Find the subtle difference: A) "I will be a doctor." B) "I am going to be a doctor."', '["A = general future, B = active plan/preparation", "A = active plan, B = general future", "Both mean the same", "Both are wrong"]', 0, 'Will = general future statement. Going to = active plan (studying now for it). Going to shows more commitment/preparation!', 'hard'),

('foundation', 'future-simple', 'beginner', 'Which is correct for immediate decision at the moment?', '["Wait! I will come with you.", "Wait! I am going to come with you.", "Both are correct", "Neither is correct"]', 0, 'Immediate spontaneous decision = will. "I will come with you" = deciding this second. Instant decision = will only!', 'hard'),

('foundation', 'future-simple', 'beginner', 'Formal announcement of schedule:', '["The conference will begin at 9 AM.", "The conference is going to begin at 9 AM.", "Both equally formal", "Neither is correct"]', 0, 'Formal schedule = will (or present simple). "The conference will begin" = official timetable. Formal events use will.', 'hard'),

-- ============================================================================
-- SUBTOPIC 5: Time Expressions: tomorrow, next, soon - 20 questions
-- ============================================================================

-- EASY (8 questions)
('foundation', 'future-simple', 'beginner', 'I will go to Delhi _____.', '["tomorrow", "yesterday", "last week", "ago"]', 0, 'Future time: tomorrow = future day. Pattern: future verb + tomorrow. Tomorrow = the day after today.', 'easy'),

('foundation', 'future-simple', 'beginner', 'She will call you _____ week.', '["next", "last", "every", "this"]', 0, 'Future time: next + week = future. Pattern: future verb + next + time unit. Next = coming week.', 'easy'),

('foundation', 'future-simple', 'beginner', 'They will arrive _____.', '["soon", "yesterday", "ago", "last week"]', 0, 'Future time: soon = near future. Pattern: future verb + soon. Soon = in the near future.', 'easy'),

('foundation', 'future-simple', 'beginner', 'He will finish _____ month.', '["next", "last", "every", "ago"]', 0, 'Future time: next + month = future. Pattern: future verb + next month. Next = coming month.', 'easy'),

('foundation', 'future-simple', 'beginner', 'We will watch the movie _____.', '["tomorrow", "yesterday", "last night", "ago"]', 0, 'Future time: tomorrow = future time. Pattern: future verb + tomorrow. Tomorrow = next day.', 'easy'),

('foundation', 'future-simple', 'beginner', 'The train will arrive _____ 5 minutes.', '["in", "ago", "last", "before"]', 0, 'Future time: in + duration = future. Pattern: future verb + in + time. In 5 minutes = 5 minutes from now.', 'easy'),

('foundation', 'future-simple', 'beginner', 'She will travel _____ year.', '["next", "last", "every", "ago"]', 0, 'Future time: next + year = future. Pattern: future verb + next year. Next = coming year.', 'easy'),

('foundation', 'future-simple', 'beginner', 'They will meet us _____.', '["later", "earlier", "ago", "yesterday"]', 0, 'Future time: later = future time. Pattern: future verb + later. Later = at a future time.', 'easy'),

-- MEDIUM (8 questions)
('foundation', 'future-simple', 'beginner', 'What is wrong? "I will go to Delhi yesterday."', '["Use tomorrow instead of yesterday", "Use next week instead of yesterday", "Use soon instead of yesterday", "Nothing wrong"]', 0, 'Tense mismatch: will = future, yesterday = past. Correct: "I will go to Delhi tomorrow." Future verb needs future time.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the correct sentence:', '["She will call you last week.", "She will call you next week.", "She will call you ago.", "She will called you next week."]', 1, 'Future time: next week = future. Correct: "She will call you next week." Next = future time marker.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: tomorrow / will / I / Delhi / to / go', '["I will go to Delhi tomorrow", "I will to Delhi go tomorrow", "Tomorrow I will go to Delhi", "I to Delhi will go tomorrow"]', 0, 'Pattern: Subject + will + verb + place + time. Order: I will go to Delhi tomorrow. Natural word order. Both orders work.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is the error? "They will finish next month ago."', '["Remove ago (use only next month)", "Use last month instead", "Use in instead of ago", "Nothing wrong"]', 0, 'Cannot mix "next" and "ago"! Correct: "They will finish next month." Next = future, ago = past. Don''t combine.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Talking about near future:', '["I will call you yesterday.", "I will call you soon.", "I will call you last week.", "I will call you ago."]', 1, 'Future time: soon = near future. Correct: "I will call you soon." Soon = in the near future (not specific time).', 'medium'),

('foundation', 'future-simple', 'beginner', 'Rearrange: next / call / She / week / will / you', '["She will call you next week", "She will you call next week", "Next week she will call you", "She call will you next week"]', 0, 'Pattern: Subject + will + verb + object + time. Order: She will call you next week. Natural structure. Both orders work.', 'medium'),

('foundation', 'future-simple', 'beginner', 'Choose the natural sentence:', '["In 5 minutes the train will arrive.", "The train will arrive in 5 minutes.", "The train will arrive 5 minutes in.", "Will arrive the train in 5 minutes."]', 1, 'Pattern: Subject + will + verb + in + duration. Natural: The train will arrive in 5 minutes. Time usually at end.', 'medium'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "He will help you last night."', '["Use tonight or later instead of last night", "Use tomorrow instead of last night", "Use next week instead of last night", "Nothing wrong"]', 0, 'Tense mismatch: will = future, last night = past. Correct: "He will help you tonight/later." Future verb needs future time.', 'medium'),

-- HARD (4 questions)
('foundation', 'future-simple', 'beginner', 'Which is correct formal announcement?', '["The meeting will hold yesterday.", "The meeting will hold tomorrow.", "The meeting will be held tomorrow.", "The meeting held tomorrow."]', 2, 'Future passive: will be + V3. Correct: "The meeting will be held tomorrow." Formal meetings use passive voice.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Find the error: "I will graduate from 2 months."', '["Use in instead of from", "Use after instead of from", "Use next instead of from", "No error"]', 0, 'Future time: in + duration (not "from"). Correct: "I will graduate in 2 months." Pattern: in + number + time unit.', 'hard'),

('foundation', 'future-simple', 'beginner', 'Arrange correctly: report / complete / will / the / We / month / next', '["We will complete the report next month", "We will complete next month the report", "Next month we will complete the report", "We the report will complete next month"]', 0, 'Pattern: Subject + will + verb + object + time. Natural: We will complete the report next month. Both orders work professionally.', 'hard'),

('foundation', 'future-simple', 'beginner', 'What is wrong? "The project will finish in last week."', '["Remove in and use just last week OR use in next week", "Use on instead of in", "Use at instead of in", "Nothing wrong"]', 0, 'Cannot use "in" with "last"! Correct: "The project finished last week" (past) OR "will finish next week" (future). In = future, last = past.', 'hard');

